args.query:
SELECT COUNT(*) AS n_swift, SUM(CASE WHEN lower(repo_data_description) LIKE '%binary%' THEN 1 ELSE 0 END) AS n_binary_marked
FROM contents
WHERE sample_path ILIKE '%.swift';

